// House GLB loader — OWNED by Dev A
'use client';

import { useGLTF } from '@react-three/drei';
import type { HouseId } from '@/lib/types';

const PATHS: Record<HouseId, string> = {
  brandenburg: '/models/brandenburg.glb',
  hamburg: '/models/hamburg.glb',
  'north-germany': '/models/north-germany.glb',
  ruhr: '/models/ruhr.glb',
};

interface Props {
  houseId: HouseId;
}

export function House({ houseId }: Props) {
  const { scene } = useGLTF(PATHS[houseId]);
  return <primitive object={scene} />;
}

// Preload all houses for smoother demo transitions
Object.values(PATHS).forEach((p) => useGLTF.preload(p));
---PANELS---
// Solar panels — OWNED by Dev A
// InstancedMesh PBR (verre bleu profond + frame alu).
// Animated drop with bounce easing during agent run.

'use client';

import { useRef } from 'react';
import { Instances, Instance } from '@react-three/drei';
import { useStore } from '@/lib/store';

export function Panels() {
  const design = useStore((s) => s.design);

  if (!design || design.modulePositions.length === 0) return null;

  // TODO Dev A:
  // - PBR material: dark blue glass + alu frame
  // - Drop animation: each panel falls from y+5 with 80ms stagger
  // - Bounce easing on landing
  // - Click handler to remove (optional, low priority per PRD)

  return (
    <Instances>
      <boxGeometry args={[1.7, 0.04, 1.0]} />
      <meshStandardMaterial color="#1a3a6e" metalness={0.6} roughness={0.2} />
      {design.modulePositions.map((p, i) => (
        <Instance key={i} position={[p.x, p.y, p.z]} />
      ))}
    </Instances>
  );
}
---SUN---
// Sun directional light driven by suncalc — OWNED by Dev A
'use client';

import { useRef } from 'react';
import { DirectionalLight } from 'three';
// import SunCalc from 'suncalc';

export function Sun() {
  const ref = useRef<DirectionalLight>(null);

  // TODO Dev A:
  // - useFrame to animate sun position over 12s during agent run
  // - SunCalc.getPosition(date, lat, lng) → azimut/altitude → directional vector
  // - shadow-mapSize 2048, shadow-bias -0.0005

  return (
    <directionalLight
      ref={ref}
      position={[20, 30, 10]}
      intensity={3}
      castShadow
      shadow-mapSize={[2048, 2048]}
    />
  );
}
---ORCH---
// Animation orchestrator — OWNED by Dev A (paired with Dev C on store)
// Runs the agent sequence: 22s of step-by-step animations synced with AgentTrace text.

'use client';

import { useEffect } from 'react';
import { useStore } from '@/lib/store';
import type { AgentStep } from '@/lib/types';

const SEQUENCE: Omit<AgentStep, 'status'>[] = [
  { id: 'load', label: 'Loading photogrammetry model...', durationMs: 2000 },
  { id: 'scan', label: 'Scanning roof geometry...', durationMs: 1500 },
  { id: 'faces', label: '4 roof faces detected', durationMs: 1500 },
  { id: 'obstructions', label: 'Obstructions: 1 chimney, 1 dormer', durationMs: 1000 },
  { id: 'yield', label: 'Computing solar yield (8760h × shadows)...', durationMs: 3000 },
  { id: 'optimal', label: 'Optimal face: SSW 195°, 47m², 1180 kWh/m²/yr', durationMs: 1500 },
  { id: 'pioneer', label: 'Pioneer inference (Reonic-native)...', durationMs: 500 },
  { id: 'predicted', label: 'Predicted in 47ms (vs Gemini 820ms baseline)', durationMs: 500 },
  { id: 'panels', label: 'Placing 24× JA Solar 440W modules...', durationMs: 2000 },
  { id: 'inverter', label: 'Selecting inverter: Sungrow SH10.0RT (95% load)', durationMs: 1500 },
  { id: 'battery', label: 'Sizing battery: BYD 6.3 kWh', durationMs: 2000 },
  { id: 'hp', label: 'Adding heat pump: Vaillant aroTHERM', durationMs: 1500 },
  { id: 'pricing', label: 'Computing BOM + pricing...', durationMs: 1500 },
  { id: 'total', label: 'Total: €11,400 · Payback 9.4 yrs', durationMs: 1500 },
  { id: 'ready', label: 'Ready. Refine below ↓', durationMs: 0 },
];

export function Orchestrator() {
  const phase = useStore((s) => s.phase);
  const setAgentSteps = useStore((s) => s.setAgentSteps);
  const updateStepStatus = useStore((s) => s.updateStepStatus);
  const setPhase = useStore((s) => s.setPhase);

  useEffect(() => {
    if (phase !== 'agent-running') return;

    const steps: AgentStep[] = SEQUENCE.map((s) => ({ ...s, status: 'pending' }));
    setAgentSteps(steps);

    let cancelled = false;
    (async () => {
      for (const step of steps) {
        if (cancelled) return;
        updateStepStatus(step.id, 'running');
        // TODO Dev A: trigger 3D animation per step (camera dive, wireframe sweep, panels drop, etc.)
        await new Promise((r) => setTimeout(r, step.durationMs));
        updateStepStatus(step.id, 'done');
      }
      setPhase('interactive');
    })();

    return () => {
      cancelled = true;
    };
  }, [phase, setAgentSteps, updateStepStatus, setPhase]);

  return null;
}

