// Read freely from anywhere. Writes only via the action methods below.

import { create } from 'zustand';
import type {
  AppPhase,
  HouseId,
  CustomerProfile,
  DesignRefinements,
  DesignResult,
  AgentStep,
} from './types';

interface AppState {
  // Phase
  phase: AppPhase;
  setPhase: (phase: AppPhase) => void;

  // House selection
  selectedHouse: HouseId | null;
  selectHouse: (id: HouseId) => void;

  // Customer profile (auto-filled, then editable)
  profile: CustomerProfile | null;
  setProfile: (p: CustomerProfile) => void;
  updateProfileField: <K extends keyof CustomerProfile>(
    key: K,
    value: CustomerProfile[K],
  ) => void;

  // Refinements (post-design)
  refinements: DesignRefinements;
  setRefinement: <K extends keyof DesignRefinements>(
    key: K,
    value: DesignRefinements[K],
  ) => void;

  // Design result (from /api/design)
  design: DesignResult | null;
  setDesign: (d: DesignResult | null) => void;

  // Agent sequence
  agentSteps: AgentStep[];
  setAgentSteps: (s: AgentStep[]) => void;
  updateStepStatus: (id: string, status: AgentStep['status']) => void;

  // Reset
  reset: () => void;
}

const defaultRefinements: DesignRefinements = {
  includeBattery: true,
  includeHeatPump: true,
  includeWallbox: false,
};

export const useStore = create<AppState>((set) => ({
  phase: 'idle',
  setPhase: (phase) => set({ phase }),

---TYPES---
// Shared TS contracts — owned jointly by Dev B (backend) and Dev C (UI)
// Pair sync sam 12h. After that, this file is FROZEN unless team-wide change.

export type HouseId = 'brandenburg' | 'hamburg' | 'north-germany' | 'ruhr';

export type HeatingType = 'oil' | 'gas' | 'heatpump' | 'other';

// Customer profile inputs (auto-filled then editable)
export interface CustomerProfile {
  annualConsumptionKwh: number; // e.g. 4500
  inhabitants: number;          // 1-6
  hasEv: boolean;
  evAnnualKm?: number;          // e.g. 15000
  heatingType: HeatingType;
  houseSizeSqm: number;
}

// Refinement toggles (post-design)
export interface DesignRefinements {
  includeBattery: boolean;
  includeHeatPump: boolean;
  includeWallbox: boolean;
}

// Roof geometry (pre-baked offline by Dev D)
export interface RoofFace {
  id: number;
  normal: [number, number, number];
  area: number;          // m²
  azimuth: number;       // 0-360°
  tilt: number;          // degrees
  vertices: number[][];  // polygon
  yieldKwhPerSqm: number; // annual
}

export interface Obstruction {
  id: string;
  type: 'chimney' | 'dormer' | 'vent';
  position: [number, number, number];
  radius: number;
}

export interface RoofGeometry {
  houseId: HouseId;
  faces: RoofFace[];
  obstructions: Obstruction[];
}

// AI design output
export interface DesignResult {
  // Modules
  moduleCount: number;
  moduleBrand: 'AIKO' | 'Trina';
  moduleWattPeak: number;
  totalKwp: number;
  modulePositions: { x: number; y: number; z: number; faceId: number }[];

  // Inverter
  inverterModel: string;
  inverterPowerKw: number;

