'use client';

import { useGLTF } from '@react-three/drei';
import { useMemo } from 'react';
import {
  EdgesGeometry,
  LineBasicMaterial,
  LineSegments,
  Mesh,
  MeshToonMaterial,
} from 'three';
import type { HouseId } from '@/lib/types';

const PATHS: Record<HouseId, string> = {
  brandenburg: '/models/brandenburg.glb',
  hamburg: '/models/hamburg.glb',
  'north-germany': '/models/north-germany.glb',
  ruhr: '/models/ruhr.glb',
};

interface Props {
  houseId: HouseId;
}

export function House({ houseId }: Props) {
  const { scene } = useGLTF(PATHS[houseId]);

  const stylized = useMemo(() => {
    const cloned = scene.clone(true);
    const toon = new MeshToonMaterial({ color: '#f5f1ea' });
    const edgeMat = new LineBasicMaterial({ color: 0x111111 });
    cloned.traverse((obj) => {
      const mesh = obj as Mesh;
      if (!mesh.isMesh) return;
      mesh.material = toon;
      mesh.castShadow = true;
      mesh.receiveShadow = true;
      const edges = new EdgesGeometry(mesh.geometry, 30);
      const lines = new LineSegments(edges, edgeMat);
      lines.raycast = () => undefined;
      mesh.add(lines);
    });
    return cloned;
  }, [scene]);

  return <primitive object={stylized} />;
}

Object.values(PATHS).forEach((p) => useGLTF.preload(p));

