'use client';

import { useFrame } from '@react-three/fiber';
import { useRef } from 'react';
import SunCalc from 'suncalc';
import type { DirectionalLight } from 'three';
import { useStore } from '@/lib/store';

const LAT = 52.52;
const LNG = 13.4;
const ANIM_DURATION_S = 12;
const START_HOUR = 9;
const END_HOUR = 16;

export function Sun() {
  const ref = useRef<DirectionalLight>(null);
  const elapsed = useRef(0);
  const phase = useStore((s) => s.phase);

  useFrame((_, delta) => {
    if (!ref.current) return;
    if (phase !== 'agent-running') {
      elapsed.current = 0;
      return;
    }
    elapsed.current = Math.min(elapsed.current + delta, ANIM_DURATION_S);
    const t = elapsed.current / ANIM_DURATION_S;
    const hour = START_HOUR + t * (END_HOUR - START_HOUR);
    const date = new Date();
    date.setHours(Math.floor(hour), Math.floor((hour % 1) * 60), 0, 0);
    const { azimuth, altitude } = SunCalc.getPosition(date, LAT, LNG);
    const x = Math.sin(azimuth) * Math.cos(altitude);
    const y = Math.sin(altitude);
    const z = Math.cos(azimuth) * Math.cos(altitude);
    ref.current.position.set(x * 30, Math.max(y * 30, 5) + 5, z * 30);
  });

  return (
    <directionalLight
      ref={ref}
      position={[20, 30, 10]}
      intensity={3}
      castShadow
      shadow-mapSize={[2048, 2048]}
      shadow-bias={-0.0005}
    />
  );
}

