    tl.to(camera.position, { x: 30, y: 25, z: 30, duration: 5 })
      .to(camera.position, { x: 25, y: 20, z: 25, duration: 4 }, '+=0.3');

    return () => {
      tl.kill();
      gsap.killTweensOf(camera.position);
    };
  }, [phase, camera]);

  return null;
