'use client';

import gsap from 'gsap';
import { useEffect, useRef } from 'react';
import type { Group } from 'three';
import { useStore } from '@/lib/store';

const PANEL = { width: 1.7, depth: 1.0, height: 0.04 };
const DROP_FROM = 5;

export function Panels() {
  const design = useStore((s) => s.design);
  const groupRef = useRef<Group>(null);

  useEffect(() => {
    if (!groupRef.current || !design || design.modulePositions.length === 0) return;
    const group = groupRef.current;
    const tweens: gsap.core.Tween[] = [];
    group.children.forEach((child, i) => {
      const target = design.modulePositions[i];
      if (!target) return;
      child.position.set(target.x, target.y + DROP_FROM, target.z);
      tweens.push(
        gsap.to(child.position, {
          y: target.y,
          duration: 0.7,
          delay: i * 0.08,
          ease: 'power2.out',
        }),
      );
    });
    return () => {
      tweens.forEach((t) => t.kill());
    };
  }, [design]);

  if (!design || design.modulePositions.length === 0) return null;

  return (
    <group ref={groupRef}>
      {design.modulePositions.map((p, i) => (
        <mesh key={i} position={[p.x, p.y, p.z]} castShadow>
          <boxGeometry args={[PANEL.width, PANEL.height, PANEL.depth]} />
          <meshToonMaterial color="#1a3a6e" />
        </mesh>
      ))}
    </group>
  );
}

