'use client';

import gsap from 'gsap';
import { useEffect, useRef } from 'react';
import type { Group } from 'three';
import { useStore } from '@/lib/store';

export function Inverter() {
  const groupRef = useRef<Group>(null);
  const step = useStore((s) => s.agentSteps.find((x) => x.id === 'inverter'));
  const active = step?.status === 'running' || step?.status === 'done';

  useEffect(() => {
    const g = groupRef.current;
    if (!g) return;
    if (active) {
      g.scale.setScalar(0);
      gsap.to(g.scale, {
        x: 1,
        y: 1,
        z: 1,
        duration: 0.4,
        ease: 'back.out(1.7)',
      });
    } else {
      g.scale.setScalar(0);
    }
  }, [active]);

  if (!step) return null;

  return (
    <group ref={groupRef} position={[3, 1.5, 2]}>
      <mesh castShadow>
        <boxGeometry args={[0.6, 1, 0.2]} />
        <meshToonMaterial color="#dadada" />
      </mesh>
      <mesh position={[0, 0.3, 0.11]}>
        <boxGeometry args={[0.05, 0.05, 0.02]} />
        <meshBasicMaterial color="#22c55e" />
      </mesh>
    </group>
  );
}

