'use client';

import gsap from 'gsap';
import { useEffect, useRef } from 'react';
import type { Group, MeshToonMaterial } from 'three';
import { useStore } from '@/lib/store';

export function HeatPump() {
  const groupRef = useRef<Group>(null);
  const bodyMatRef = useRef<MeshToonMaterial>(null);
  const fanMatRef = useRef<MeshToonMaterial>(null);
  const step = useStore((s) => s.agentSteps.find((x) => x.id === 'hp'));
  const include = useStore((s) => s.refinements.includeHeatPump);
  const active = step?.status === 'running' || step?.status === 'done';

  useEffect(() => {
    const g = groupRef.current;
    if (!g) return;
    if (active) {
      g.scale.setScalar(0.7);
      gsap.to(g.scale, {
        x: 1,
        y: 1,
        z: 1,
        duration: 0.5,
        ease: 'power2.out',
      });
      [bodyMatRef.current, fanMatRef.current].forEach((m) => {
        if (!m) return;
        m.transparent = true;
        m.opacity = 0;
        gsap.to(m, {
          opacity: 1,
          duration: 0.5,
          ease: 'power2.out',
          onComplete: () => {
            m.transparent = false;
          },
        });
      });
    }
  }, [active]);

  if (!include || !step) return null;

  return (
    <group ref={groupRef} position={[-3, 0.3, 3]}>
      <mesh castShadow>
        <boxGeometry args={[0.8, 0.6, 0.5]} />
        <meshToonMaterial ref={bodyMatRef} color="#cccccc" />
      </mesh>
      <mesh position={[0, 0, 0.26]} rotation={[Math.PI / 2, 0, 0]}>
        <cylinderGeometry args={[0.2, 0.2, 0.02, 24]} />
        <meshToonMaterial ref={fanMatRef} color="#888888" />
      </mesh>
    </group>
  );
}

