'use client';

import { Canvas } from '@react-three/fiber';
import { ContactShadows, Environment } from '@react-three/drei';
import { Bloom, EffectComposer, ToneMapping } from '@react-three/postprocessing';
import { ToneMappingMode } from 'postprocessing';
import { Suspense } from 'react';
import { Battery } from './Battery';
import { CameraRig } from './CameraRig';
import { Heatmap } from './Heatmap';
import { HeatPump } from './HeatPump';
import { House } from './House';
import { Inverter } from './Inverter';
import { Panels } from './Panels';
import { Sun } from './Sun';
import { Wallbox } from './Wallbox';
import type { HouseId } from '@/lib/types';

interface Props {
  houseId: HouseId;
}

export function Scene3D({ houseId }: Props) {
  return (
    <Canvas
      shadows
      camera={{ position: [40, 30, 40], fov: 35 }}
      gl={{ antialias: true, toneMappingExposure: 1.1 }}
    >
      <color attach="background" args={['#e8eef5']} />
      <Suspense fallback={null}>
        <Environment preset="apartment" background={false} />
        <ambientLight intensity={0.4} />
        <Sun />
        <House houseId={houseId} />
        <Panels />
        <Inverter />
        <Battery />
        <HeatPump />
        <Wallbox />
        <Heatmap />
        <mesh rotation={[-Math.PI / 2, 0, 0]} receiveShadow>
          <planeGeometry args={[200, 200]} />
          <meshStandardMaterial color="#fafafa" />
        </mesh>
        <ContactShadows
          position={[0, 0.01, 0]}
          opacity={0.4}
          scale={40}
          blur={2.5}
          far={20}
        />
      </Suspense>
      <CameraRig />
      <EffectComposer>
        <Bloom luminanceThreshold={0.9} intensity={0.4} mipmapBlur />
        <ToneMapping mode={ToneMappingMode.ACES_FILMIC} />
      </EffectComposer>
    </Canvas>
  );
}

