54	  { id: 'stylize',         phase: 'RENDER',  kind: 'render', label: 'AI generating stylized mesh from photogrammetry + analysis...', durationMs: 1500 },
55	  { id: 'stylize_out',     phase: 'RENDER',  kind: 'done',   label: 'Architectural mockup ready · footprint 7×5 m · roof 35°',    durationMs: 600  },
56	  { id: 'panels_drop',     phase: 'RENDER',  kind: 'render', label: 'Dropping panels onto rendered roof...',                       durationMs: 1900 },
57	  { id: 'finalize',        phase: 'RENDER',  kind: 'render', label: 'Lighting · materials · contact shadows...',                  durationMs: 800  },
58	  { id: 'ready',           phase: 'RENDER',  kind: 'done',   label: 'Ready. Edit anything below ↓',                               durationMs: 0    },
59	];
60	
61	export function Orchestrator() {
62	  const phase = useStore((s) => s.phase);
63	  const profile = useStore((s) => s.profile);
64	  const selectedHouse = useStore((s) => s.selectedHouse);
65	  const customAddress = useStore((s) => s.customAddress);
66	  const setAgentSteps = useStore((s) => s.setAgentSteps);
67	  const updateStepStatus = useStore((s) => s.updateStepStatus);
68	  const setPhase = useStore((s) => s.setPhase);
69	  const setDesign = useStore((s) => s.setDesign);
70	  const setCustomRoofGeometry = useStore((s) => s.setCustomRoofGeometry);
71	
72	  useEffect(() => {
73	    if (phase !== 'agent-running' || !profile || !selectedHouse) return;
74	
75	    const steps: AgentStep[] = SEQUENCE.map((s) => ({
76	      id: s.id,
77	      label: s.label,
78	      durationMs: s.durationMs,
79	      status: 'pending',
80	    }));
81	    setAgentSteps(steps);
82	
83	    let cancelled = false;
84	
85	    // Build the request body — custom addresses ship lat/lng so the API can
86	    // synthesise a plausible RoofGeometry on the fly (cf src/lib/customRoof.ts).
87	    const body: Record<string, unknown> = { profile, houseId: selectedHouse };
88	    if (selectedHouse === 'custom' && customAddress) {
89	      body.lat = customAddress.lat;
90	      body.lng = customAddress.lng;
91	      body.address = customAddress.formatted;
92	    }
93	
94	    // Fire the real /api/design call in parallel — visible animation drives the UX,
95	    // but the actual data lands in the store before phase=interactive.
96	    const designPromise = fetch('/api/design', {
97	      method: 'POST',
98	      headers: { 'content-type': 'application/json' },
99	      body: JSON.stringify(body),
100	    })
101	      .then((r) => (r.ok ? r.json() : null))
102	      .catch(() => null);
103	
104	    (async () => {
105	      for (const step of steps) {
106	        if (cancelled) return;
107	        updateStepStatus(step.id, 'running');
108	        await new Promise((r) => setTimeout(r, step.durationMs));
109	        updateStepStatus(step.id, 'done');
110	      }
111	      const design = await designPromise;
112	      if (cancelled) return;
113	      if (design) {
114	        // Persist the synthesised geometry so HouseGeometryProvider can
115	        // render the right footprint for custom addresses.
116	        if (design.geometry) {
117	          setCustomRoofGeometry(design.geometry);
118	        }
119	        setDesign(design);
120	      }
121	      setPhase('interactive');
122	    })();
123	
124	    return () => {
125	      cancelled = true;
126	    };
127	  }, [
128	    phase,
129	    profile,
130	    selectedHouse,
131	    customAddress,
132	    setAgentSteps,
133	    updateStepStatus,
134	    setPhase,
135	    setDesign,
136	    setCustomRoofGeometry,
137	  ]);
138	
139	  return null;
140	}
141	
142	// Export for AgentTrace.tsx to read kind/phase metadata on each step
143	export { SEQUENCE };
144	export type { SeqStep };

